class Solution {
    public String baseNeg2(int n) {
        if (n == 0) return "0";
        StringBuilder sb = new StringBuilder();
        while (n > 0) {
            n -= Math.min(n, 2);
            sb.insert(0, n & 1);
            n >>= 1;
        }
        return sb.toString();
    }
}
